const crmRoot = $('Gera Resumo Histórico Longo').first().json || {};
const crm = crmRoot.inputs || {};
const memory = $('Get Memory').first()?.json || {};
const norm = $('Normaliza Entrada FUP').first()?.json || {};

const labels = Array.isArray(norm.labels)
  ? norm.labels.map(x => String(x || '').toLowerCase().trim())
  : [];

const statusLead = String(crm.status_lead || '').trim();
const ultimaIntencao = String(crm.ultima_intencao || '').trim();
const eventoSistema = String(crm.evento_sistema || '').trim();

const contadorFollowup = Number(memory.contador_followup || 0);
const tipoUltimoFollowup = String(memory.tipo_ultimo_followup || '').trim();
const ultimoFollowupEmRaw = memory.ultimo_followup_em || null;

const agora = new Date();
let horasDesdeUltimoFup = null;

if (ultimoFollowupEmRaw) {
  const ultimo = new Date(ultimoFollowupEmRaw);
  if (!isNaN(ultimo.getTime())) {
    horasDesdeUltimoFup = (agora.getTime() - ultimo.getTime()) / 3600000;
  }
}

const janelaMinimaPorStatus = {
  NOVO_LEAD: 24,
  COLETANDO_DADOS: 24,
  QUALIFICANDO: 24,
  PRE_REPROVADO: 24,
  APTO_PARA_AVALIACAO: 18,
  AGUARDANDO_PAGAMENTO: 12,
  COMPROVANTE_RECEBIDO: 8,
  AGUARDANDO_ESCOLHA_HORARIO: 8,
  PRE_RESERVA_CRIADA: 24,
  TRANSFERIDO_FLAVIA: 48,
  ENCERRADO_NAO_PERFIL: 72,
  ENCERRADO_SEM_RESPOSTA: 48,
  ENCERRADO: 48
};

const janelaMinimaHoras = janelaMinimaPorStatus[statusLead] || 24;
const janelaOk = horasDesdeUltimoFup === null || horasDesdeUltimoFup >= janelaMinimaHoras;

const restricoesFup = [];
const alertasContexto = [];
const sinaisOperacionais = [];
const proximaAcaoSugerida = [];
const resumoLeadAtual = crm.resumo_lead || {};
const resumoInternoRepasse = crm.resumo_interno_repasse || {};

if (!janelaOk && horasDesdeUltimoFup !== null) {
  alertasContexto.push(`Janela recomendada ainda não atingida: ${horasDesdeUltimoFup.toFixed(1)}h de ${janelaMinimaHoras}h`);
}

if (contadorFollowup >= 3) {
  alertasContexto.push('Lead já recebeu 3 ou mais FUPs');
  restricoesFup.push('usar tom de fechamento elegante');
}

if (tipoUltimoFollowup) {
  alertasContexto.push(`Último followup enviado: ${tipoUltimoFollowup}`);
}

if (labels.includes('01-em-atendimento') || labels.includes('01-bruna-atendimento')) {
  alertasContexto.push('Conversa marcada como atendimento em andamento');
}

if (labels.includes('transferido-flavia') || labels.includes('flavia') || labels.includes('humano')) {
  alertasContexto.push('Conversa com sinal de atuação humana');
  restricoesFup.push('não soar como automação invasiva');
}

if (crm.deve_repassar_humano === true) {
  restricoesFup.push('crm sinalizou repasse humano');
  proximaAcaoSugerida.push('manter tom leve e respeitoso');
}

if (crm.deve_consultar_agenda === true) {
  restricoesFup.push('não inventar horários');
  proximaAcaoSugerida.push('se falar de agenda, apenas estimular resposta do lead');
}

if (crm.deve_criar_pre_reserva === true) {
  restricoesFup.push('não inventar confirmação operacional');
}

if (crm.deve_solicitar_pagamento === true) {
  restricoesFup.push('se falar de pagamento, manter tom leve');
}

if (crm.deve_encerrar_conversa === true) {
  restricoesFup.push('usar tom respeitoso e sem insistência');
}

if (statusLead === 'ENCERRADO_NAO_PERFIL') {
  restricoesFup.push('não contradizer fora de perfil');
  restricoesFup.push('deixar porta aberta apenas se o cenário mudar');
}

if (ultimaIntencao === 'FORA_DO_PERFIL') {
  restricoesFup.push('não oferecer avanço operacional incompatível com o perfil atual');
}

if (ultimaIntencao === 'OBJECAO_PRECO' || ultimaIntencao === 'PEDIU_VALOR') {
  restricoesFup.push('não voltar cobrando como se a objeção não existisse');
}

let tipoFollowupSugerido = 'FUP_1_RETOMADA_LEVE';
if (contadorFollowup === 1) tipoFollowupSugerido = 'FUP_2_DESTRAVA_OBJETIVO';
if (contadorFollowup >= 2) tipoFollowupSugerido = 'FUP_3_FECHAMENTO_ELEGANTE';

let estrategiaFup = 'RETOMADA_LEVE';
let objetivoFup = 'retomar a conversa com baixa fricção';
let recomendacaoTom = 'leve, humano e direto';

if (statusLead === 'NOVO_LEAD') {
  estrategiaFup = 'RETOMADA_LEVE';
  objetivoFup = 'retomar a conversa sem parecer primeiro atendimento';
}

if (statusLead === 'COLETANDO_DADOS' || statusLead === 'QUALIFICANDO') {
  estrategiaFup = 'RETOMADA_LEVE';
  objetivoFup = 'reabrir a conversa sem parecer cobrança';
}

if (statusLead === 'APTO_PARA_AVALIACAO') {
  estrategiaFup = 'DESTRAVAR_DECISAO';
  objetivoFup = 'entender se o lead quer seguir com a avaliação';
  recomendacaoTom = 'consultivo e objetivo';
}

if (statusLead === 'AGUARDANDO_PAGAMENTO') {
  estrategiaFup = 'LEMBRAR_PAGAMENTO';
  objetivoFup = 'retomar o próximo passo sem soar como cobrança dura';
  recomendacaoTom = 'operacional leve';
}

if (statusLead === 'COMPROVANTE_RECEBIDO') {
  estrategiaFup = 'DESTRAVAR_PROXIMO_PASSO';
  objetivoFup = 'estimular avanço para a etapa seguinte sem inventar processo';
  recomendacaoTom = 'objetivo e leve';
}

if (statusLead === 'AGUARDANDO_ESCOLHA_HORARIO') {
  estrategiaFup = 'LEMBRAR_ESCOLHA_HORARIO';
  objetivoFup = 'estimular a escolha de horário sem inventar agenda';
  recomendacaoTom = 'curto e direto';
}

if (statusLead === 'ENCERRADO_NAO_PERFIL' || ultimaIntencao === 'FORA_DO_PERFIL') {
  estrategiaFup = 'PORTA_ABERTA_FUTURA';
  objetivoFup = 'manter porta aberta para futuro sem contrariar a regra atual';
  recomendacaoTom = 'respeitoso e elegante';
}

if (statusLead === 'ENCERRADO' || statusLead === 'ENCERRADO_SEM_RESPOSTA') {
  estrategiaFup = contadorFollowup >= 2 ? 'FECHAMENTO_ELEGANTE' : 'REATIVACAO_LEVE';
  objetivoFup = contadorFollowup >= 2
    ? 'encerrar de forma elegante e sem insistência'
    : 'reativar a conversa com suavidade';
  recomendacaoTom = contadorFollowup >= 2 ? 'elegante e breve' : 'leve e amistoso';
}

if (ultimaIntencao === 'OBJECAO_PRECO' || ultimaIntencao === 'PEDIU_VALOR') {
  estrategiaFup = 'DESTRAVAR_DECISAO';
  objetivoFup = 'destravar a decisão respeitando a objeção atual';
  recomendacaoTom = 'consultivo e sem pressão';
}

if (crm.deve_enviar_guia === true) {
  sinaisOperacionais.push('guia pode ser útil');
}

if (crm.deve_repassar_humano === true) {
  sinaisOperacionais.push('repasse humano sinalizado');
}

if (crm.deve_consultar_agenda === true) {
  sinaisOperacionais.push('há contexto de agenda');
}

if (crm.deve_criar_pre_reserva === true) {
  sinaisOperacionais.push('há contexto de pré-reserva');
}

if (crm.deve_solicitar_pagamento === true) {
  sinaisOperacionais.push('há contexto de pagamento');
}

const contextoOperacional = {
  status_base: statusLead,
  ultima_intencao_base: ultimaIntencao,
  evento_sistema_base: eventoSistema,
  contador_followup_atual: contadorFollowup,
  tipo_ultimo_followup: tipoUltimoFollowup,
  ultimo_followup_em: ultimoFollowupEmRaw,
  horas_desde_ultimo_followup: horasDesdeUltimoFup,
  janela_minima_horas: janelaMinimaHoras,
  janela_ok: janelaOk,
  tipo_followup_sugerido: tipoFollowupSugerido,
  estrategia_fup: estrategiaFup,
  objetivo_fup: objetivoFup,
  recomendacao_tom: recomendacaoTom,
  usar_followup_cauteloso: !janelaOk || contadorFollowup >= 3 || crm.deve_encerrar_conversa === true,
  restricoes_fup: restricoesFup,
  alertas_contexto: alertasContexto,
  sinais_operacionais: sinaisOperacionais,
  proxima_acao_sugerida: proximaAcaoSugerida,
  labels_conversa: labels,
  resumo_lead_atual: resumoLeadAtual,
  resumo_interno_repasse: resumoInternoRepasse
};

const guiaIa = [
  `status_base=${statusLead || ''}`,
  `ultima_intencao_base=${ultimaIntencao || ''}`,
  `evento_sistema_base=${eventoSistema || ''}`,
  `tipo_followup_sugerido=${tipoFollowupSugerido}`,
  `estrategia_fup=${estrategiaFup}`,
  `objetivo_fup=${objetivoFup}`,
  `recomendacao_tom=${recomendacaoTom}`,
  `janela_ok=${janelaOk}`,
  `contador_followup=${contadorFollowup}`,
  `tipo_ultimo_followup=${tipoUltimoFollowup || ''}`,
  `usar_followup_cauteloso=${!janelaOk || contadorFollowup >= 3 || crm.deve_encerrar_conversa === true}`,
  `restricoes=${restricoesFup.join(' | ') || ''}`,
  `alertas=${alertasContexto.join(' | ') || ''}`,
  `sinais_operacionais=${sinaisOperacionais.join(' | ') || ''}`,
  `proxima_acao_sugerida=${proximaAcaoSugerida.join(' | ') || ''}`
].join('\n');

return [
  {
    json: {
      status_base: statusLead,
      ultima_intencao_base: ultimaIntencao,
      evento_sistema_base: eventoSistema,
      contador_followup_atual: contadorFollowup,
      tipo_ultimo_followup: tipoUltimoFollowup,
      ultimo_followup_em: ultimoFollowupEmRaw,
      horas_desde_ultimo_followup: horasDesdeUltimoFup,
      janela_minima_horas: janelaMinimaHoras,
      janela_ok: janelaOk,
      tipo_followup_sugerido: tipoFollowupSugerido,
      estrategia_fup: estrategiaFup,
      objetivo_fup: objetivoFup,
      recomendacao_tom: recomendacaoTom,
      restricoes_fup: restricoesFup,
      alertas_contexto: alertasContexto,
      sinais_operacionais: sinaisOperacionais,
      proxima_acao_sugerida: proximaAcaoSugerida,
      usar_followup_cauteloso: !janelaOk || contadorFollowup >= 3 || crm.deve_encerrar_conversa === true,
      labels_conversa: labels,
      resumo_lead_atual: resumoLeadAtual,
      resumo_interno_repasse: resumoInternoRepasse,
      contexto_operacional: contextoOperacional,
      guia_ia: guiaIa
    }
  }
];

