// NODE: Preparar Envio FUP
const parsed = $('PARSE FUP JSON').first().json || {};
const norm = $('Normaliza Entrada FUP').first().json || {};
const ctx = $('Preparar Contexto FUP').first().json || {};

const mensagem_fup = String(parsed.mensagem_fup || '').trim();
const pode_enviar = !!parsed.pode_enviar && !!mensagem_fup;

return [
  {
    json: {
      pode_enviar,
      account_id: Number(norm.account_id || 0),
      conversation_id: Number(norm.conversation_id || 0),
      contact_id: Number(norm.contact_id || 0),
      phone: String(norm.phone || '').trim(),
      lead_name: String(norm.lead_name || '').trim(),

      mensagem_fup,
      mensagens_resposta: Array.isArray(parsed.mensagens_resposta) ? parsed.mensagens_resposta : [],

      tipo_followup: String(parsed.tipo_followup || ctx.tipo_followup_sugerido || 'FUP_1_RETOMADA_LEVE'),
      status_lead_novo: String(parsed.status_lead_novo || ctx.status_base || 'QUALIFICANDO'),
      ultima_intencao_nova: String(parsed.ultima_intencao_nova || 'SUMIU'),
      evento_sistema_novo: 'FOLLOWUP_DISPARADO',
      resumo_followup: String(parsed.resumo_followup || 'Followup gerado pela Bruna.').trim(),

      tags_add: Array.isArray(parsed.tags_add) ? parsed.tags_add : [],
      tags_remove: Array.isArray(parsed.tags_remove) ? parsed.tags_remove : [],

      contador_followup_atual: Number(ctx.contador_followup_atual || 0),
      tipo_ultimo_followup: String(ctx.tipo_ultimo_followup || '').trim(),
      ultimo_followup_em: ctx.ultimo_followup_em || null,

      raw_model_output: parsed.raw_model_output || ''
    }
  }
];

// NODE: Preparar Labels FUP
const prep = $('Preparar Envio FUP').first().json || {};
const norm = $('Normaliza Entrada FUP').first().json || {};

const atuais = Array.isArray(norm.labels) ? norm.labels.map(x => String(x).trim()).filter(Boolean) : [];
const add = Array.isArray(prep.tags_add) ? prep.tags_add.map(x => String(x).trim()).filter(Boolean) : [];
const remove = Array.isArray(prep.tags_remove) ? prep.tags_remove.map(x => String(x).trim()).filter(Boolean) : [];

const finais = [...new Set([
  ...atuais.filter(x => !remove.includes(x)),
  ...add
])];

return [
  {
    json: {
      ...prep,
      labels_finais: finais
    }
  }
];

const src = $('Gerador de FUP').first().json || {};

const rawCandidates = [
  src.output,
  src.text,
  src.response,
  src.content,
  src.message?.content,
  Array.isArray(src.messages) ? src.messages[0]?.content : undefined,
  typeof src === 'string' ? src : undefined
].filter(v => typeof v === 'string' && v.trim());

let raw = rawCandidates[0] || JSON.stringify(src);
raw = String(raw).trim();
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('Nao foi encontrado um objeto JSON na saida do modelo');
}

let jsonText = jsonMatch[0]
  .replace(/[\u201C\u201D]/g, '"')
  .replace(/[\u2018\u2019]/g, "'")
  .replace(/,\s*([}\]])/g, '$1')
  .trim();

let parsed;
try {
  parsed = JSON.parse(jsonText);
} catch (e) {
  throw new Error('Falha ao fazer parse do JSON do modelo: ' + e.message + ' | RAW: ' + jsonText);
}

const ctx = $('Preparar Contexto FUP').first().json || {};

const tiposValidos = [
  'FUP_1_RETOMADA_LEVE',
  'FUP_2_DESTRAVA_OBJETIVO',
  'FUP_3_FECHAMENTO_ELEGANTE'
];

const statusValidos = [
  'NOVO_LEAD',
  'COLETANDO_DADOS',
  'QUALIFICANDO',
  'PRE_REPROVADO',
  'APTO_PARA_AVALIACAO',
  'AGUARDANDO_PAGAMENTO',
  'COMPROVANTE_RECEBIDO',
  'AGUARDANDO_ESCOLHA_HORARIO',
  'PRE_RESERVA_CRIADA',
  'TRANSFERIDO_FLAVIA',
  'ENCERRADO_NAO_PERFIL',
  'ENCERRADO_SEM_RESPOSTA',
  'ENCERRADO'
];

const intencoesValidas = [
  'INTERESSE_CRECHE',
  'INTERESSE_HOTEL',
  'PEDIU_VALOR',
  'PEDIU_LOCALIZACAO',
  'PEDIU_VISITA',
  'INFORMOU_DADOS_CAO',
  'INFORMOU_DADOS_TUTOR',
  'ACEITOU_AVALIACAO',
  'RECEBEU_PIX',
  'ENVIOU_COMPROVANTE',
  'ESCOLHEU_HORARIO',
  'PEDIU_HUMANO',
  'FORA_DO_PERFIL',
  'URGENCIA_FERIADO',
  'OBJECAO_PRECO',
  'SUMIU'
];

const defaultTagsAdd = {
  FUP_1_RETOMADA_LEVE: ['fup-bruna-1'],
  FUP_2_DESTRAVA_OBJETIVO: ['fup-bruna-2'],
  FUP_3_FECHAMENTO_ELEGANTE: ['fup-bruna-3']
};

let tipo_followup = String(parsed.tipo_followup || '').trim();
if (!tiposValidos.includes(tipo_followup)) {
  tipo_followup = ctx.tipo_followup_sugerido || 'FUP_1_RETOMADA_LEVE';
}

let mensagens_resposta = Array.isArray(parsed.mensagens_resposta)
  ? parsed.mensagens_resposta.map(x => String(x || '').trim()).filter(Boolean).slice(0, 2)
  : [];

let pode_enviar = typeof parsed.pode_enviar === 'boolean'
  ? parsed.pode_enviar
  : mensagens_resposta.length > 0;

let status_lead_novo = String(parsed.status_lead_novo || '').trim();
if (!statusValidos.includes(status_lead_novo)) {
  status_lead_novo = ctx.status_base || 'QUALIFICANDO';
}

let ultima_intencao_nova = String(parsed.ultima_intencao_nova || '').trim();
if (!intencoesValidas.includes(ultima_intencao_nova)) {
  ultima_intencao_nova = 'SUMIU';
}

const evento_sistema_novo = 'FOLLOWUP_DISPARADO';

let resumo_followup = String(parsed.resumo_followup || '').trim();
if (!resumo_followup) {
  resumo_followup = 'Followup gerado pela Bruna.';
}

let tags_add = Array.isArray(parsed.tags_add)
  ? parsed.tags_add.map(x => String(x || '').trim()).filter(Boolean)
  : [];
if (!tags_add.length) {
  tags_add = defaultTagsAdd[tipo_followup] || ['fup-bruna-1'];
}

let tags_remove = Array.isArray(parsed.tags_remove)
  ? parsed.tags_remove.map(x => String(x || '').trim()).filter(Boolean)
  : [];

if (!tags_remove.includes('fup-bruna-bloqueado')) {
  tags_remove.push('fup-bruna-bloqueado');
}

if (!pode_enviar) {
  mensagens_resposta = [];
}

const mensagem_fup = mensagens_resposta.join('\n\n');

return [
  {
    json: {
      pode_enviar,
      tipo_followup,
      mensagens_resposta,
      mensagem_fup,
      status_lead_novo,
      ultima_intencao_nova,
      evento_sistema_novo,
      resumo_followup,
      tags_add,
      tags_remove,
      raw_model_output: raw
    }
  }
];

const fup = $json || {};

const norm = (() => {
  try {
    return $('Normaliza Entrada FUP').first().json || {};
  } catch (e) {
    return {};
  }
})();

const ctx = (() => {
  try {
    return $('Preparar Contexto FUP').first().json || {};
  } catch (e) {
    return {};
  }
})();

